        track.ensureStaveCount(1.0)
        var staff: com.omnifret.gplayer.model.Staff = track.staves[(0).toInt()]
        staff.showStandardNotation = true
        var trackId: String = node.getAttribute("id")
        for (c in node.childElements())
        {
            when (c.localName)
            {
                "Name" -> 
                {
