                "Color" -> 
                {
                    var parts: com.omnifret.gplayer.collections.List<String> = com.omnifret.gplayer.importer.GpifParser._splitSafe(c.innerText)
                    if (parts.length >= 3)
                    {
                        var r: Double = com.omnifret.gplayer.importer.GpifParser._parseIntSafe(parts[(0).toInt()], 0.0)
                        var g: Double = com.omnifret.gplayer.importer.GpifParser._parseIntSafe(parts[(1).toInt()], 0.0)
                        var b: Double = com.omnifret.gplayer.importer.GpifParser._parseIntSafe(parts[(2).toInt()], 0.0)
                        track.color = com.omnifret.gplayer.model.Color(r, g, b, 255.0)
                    }
                }
                "Instrument" -> 
                {
                    var instrumentName: String = c.getAttribute("ref")
                    if (instrumentName.endsWith("-gs") || instrumentName.endsWith("GrandStaff"))
                    {
                        track.ensureStaveCount(2.0)
                        track.staves[(1).toInt()].showStandardNotation = true
                    }
                }
                "InstrumentSet" -> 
                {
                    this._parseInstrumentSet(track, c)
                }
                "NotationPatch" -> 
                {
                    this._parseNotationPatch(track, c)
                }
                "ShortName" -> 
                {
                    track.shortName = c.innerText
                }
                "SystemsDefautLayout" -> 
                {
                    track.defaultSystemsLayout = com.omnifret.gplayer.importer.GpifParser._parseIntSafe(c.innerText, 4.0)
                }
                "SystemsLayout" -> 
                {
                    track.systemsLayout = com.omnifret.gplayer.importer.GpifParser._splitSafe(c.innerText).map(fun(i: String): Double{
                        return com.omnifret.gplayer.importer.GpifParser._parseIntSafe(i, 4.0)
                    }
                    )
                }
                "Lyrics" -> 
                {
                    this._parseLyrics(trackId, c)
                }
                "Properties" -> 
                {
                    this._parseTrackProperties(track, c)
                }
                "GeneralMidi", "MidiConnection", "MIDISettings" -> 
                {
                    this._parseGeneralMidi(track, c)
                }
                "Sounds" -> 
                {
                    this._parseSounds(trackId, track, c)
                }
                "PlaybackState" -> 
                {
                    var state: String = c.innerText
                    track.playbackInfo.isSolo = state == "Solo"
                    track.playbackInfo.isMute = state == "Mute"
                }
                "PartSounding" -> 
                {
                    this._parsePartSounding(trackId, track, c)
                }
                "Staves" -> 
                {
                    this._parseStaves(track, c)
                }
                "Transpose" -> 
                {
