    private fun _parseArticulation(track: com.omnifret.gplayer.model.Track, node: com.omnifret.gplayer.xml.XmlNode, isInstrumentSet: Boolean, elementName: String): Unit{
        var articulation: com.omnifret.gplayer.model.InstrumentArticulation = com.omnifret.gplayer.model.InstrumentArticulation()
        articulation.outputMidiNumber = -1.0
        articulation.elementType = elementName
