                {
                    name = c.innerText
                }
                "InputMidiNumbers" -> 
                {
                    articulation.id = com.omnifret.gplayer.importer.GpifParser._parseIntSafe(txt.splitBy(" ")[(0).toInt()], 0.0)
                }
                "OutputMidiNumber" -> 
                {
                    articulation.outputMidiNumber = com.omnifret.gplayer.importer.GpifParser._parseIntSafe(txt, 0.0)
                }
                "TechniqueSymbol" -> 
                {
                    articulation.techniqueSymbol = com.omnifret.gplayer.importer.GpifParser.parseTechniqueSymbol(txt)
                }
                "TechniquePlacement" -> 
                {
                    articulation.techniqueSymbolPlacement = com.omnifret.gplayer.importer.GpifParser.parseTechniqueSymbolPlacement(txt)
                }
                "Noteheads" -> 
                {
                    var noteHeadsTxt: com.omnifret.gplayer.collections.List<String> = com.omnifret.gplayer.importer.GpifParser._splitSafe(txt)
                    if (noteHeadsTxt.length >= 1)
                    {
