                    {
                        articulation.noteHeadHalf = com.omnifret.gplayer.importer.GpifParser.parseNoteHead(noteHeadsTxt[(1).toInt()])
                    }
                    if (noteHeadsTxt.length >= 3)
                    {
                        articulation.noteHeadWhole = com.omnifret.gplayer.importer.GpifParser.parseNoteHead(noteHeadsTxt[(2).toInt()])
                    }
                    if (articulation.noteHeadHalf == com.omnifret.gplayer.model.MusicFontSymbol.None)
                    {
                        articulation.noteHeadHalf = articulation.noteHeadDefault
                    }
                    if (articulation.noteHeadWhole == com.omnifret.gplayer.model.MusicFontSymbol.None)
