    /**
     */
    private fun _parseDiagramItemForChord(chord: com.omnifret.gplayer.model.Chord, node: com.omnifret.gplayer.xml.XmlNode): Unit{
        chord.name = node.getAttribute("name")
        var diagram: com.omnifret.gplayer.xml.XmlNode? = node.findChildElement("Diagram")
        if (!com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(diagram)))
        {
            chord.showDiagram = false
            chord.showFingering = false
            return
        }
        var stringCount: Double = com.omnifret.gplayer.importer.GpifParser._parseIntSafe(diagram!!.getAttribute("stringCount"), 6.0)
        var baseFret: Double = com.omnifret.gplayer.importer.GpifParser._parseIntSafe(diagram!!.getAttribute("baseFret"), 0.0)
        chord.firstFret = baseFret + 1.0
        if (true) {
            var i: Double = 0.0
            
            while(i < stringCount){
                chord.strings.push(-1.0)
                i++
            }
        }
        for (c in diagram!!.childElements())
        {
            when (c.localName)
            {
                "Fret" -> 
                {
                    var guitarString: Double = com.omnifret.gplayer.importer.GpifParser._parseIntSafe(c.getAttribute("string"), 0.0)
                    chord.strings[(stringCount - guitarString - (1.0).toDouble()).toInt()] = baseFret + com.omnifret.gplayer.importer.GpifParser._parseIntSafe(c.getAttribute("fret"), 0.0)
                }
                "Fingering" -> 
                {
                    var existingFingers: com.omnifret.gplayer.collections.ObjectBooleanMap<com.omnifret.gplayer.model.Fingers> = com.omnifret.gplayer.collections.ObjectBooleanMap<com.omnifret.gplayer.model.Fingers>()
                    for (p in c.childElements())
                    {
                        when (p.localName)
                        {
                            "Position" -> 
                            {
                                var finger: com.omnifret.gplayer.model.Fingers = com.omnifret.gplayer.model.Fingers.Unknown
                                var fret: Double = baseFret + com.omnifret.gplayer.importer.GpifParser._parseIntSafe(p.getAttribute("fret"), 0.0)
                                when (p.getAttribute("finger"))
                                {
                                    "Index" -> 
                                    {
                                        finger = com.omnifret.gplayer.model.Fingers.IndexFinger
                                    }
                                    "Middle" -> 
                                    {
                                        finger = com.omnifret.gplayer.model.Fingers.MiddleFinger
                                    }
                                    "Rank" -> 
                                    {
                                        finger = com.omnifret.gplayer.model.Fingers.AnnularFinger
                                    }
                                    "Pinky" -> 
                                    {
                                        finger = com.omnifret.gplayer.model.Fingers.LittleFinger
                                    }
                                    "Thumb" -> 
                                    {
                                        finger = com.omnifret.gplayer.model.Fingers.Thumb
                                    }
                                    "None" -> 
                                    {
                                    }
                                    else -> { }
                                }
                                if (finger != com.omnifret.gplayer.model.Fingers.Unknown)
                                {
                                    if (existingFingers.has(finger))
                                    {
                                        chord.barreFrets.push(fret)
                                    }
                                    else 
                                    {
                                        existingFingers.set(finger, true)
                                    }
                                }
                            }
                            else -> { }
                        }
                    }
                }
                "Property" -> 
                {
                    when (c.getAttribute("name"))
                    {
                        "ShowName" -> 
                        {
                            chord.showName = c.getAttribute("value") == "true"
                        }
                        "ShowDiagram" -> 
                        {
                            chord.showDiagram = c.getAttribute("value") == "true"
                        }
                        "ShowFingering" -> 
                        {
                            chord.showFingering = c.getAttribute("value") == "true"
                        }
                        else -> { }
                    }
                }
                else -> { }
            }
        }
    }
    
