                    rhythm.tupletNumerator = com.omnifret.gplayer.importer.GpifParser._parseIntSafe(c.getAttribute("num"), -1.0)
                    rhythm.tupletDenominator = com.omnifret.gplayer.importer.GpifParser._parseIntSafe(c.getAttribute("den"), -1.0)
                }
                "AugmentationDot" -> 
                {
                    rhythm.dots = com.omnifret.gplayer.importer.GpifParser._parseIntSafe(c.getAttribute("count"), 0.0)
                }
                else -> { }
            }
        }
        this._rhythmById.set(rhythmId, rhythm)
    }
    
    private fun _buildModel(): Unit{
        if (true) {
            var i: Double = 0.0
            var j: Double = this._masterBars.length
            
            while(i < j){
                var masterBar: com.omnifret.gplayer.model.MasterBar = this._masterBars[(i).toInt()]
                this.score.addMasterBar(masterBar)
                i++
            }
        }
        var lastMasterBar: com.omnifret.gplayer.model.MasterBar = this._masterBars[(this._masterBars.length - (1.0).toDouble()).toInt()]
        if (this._doubleBars.has(lastMasterBar))
        {
            this._doubleBars.delete(lastMasterBar)
            lastMasterBar.isDoubleBar = false
        }
        var trackIndexToTrackId: com.omnifret.gplayer.collections.List<String> = com.omnifret.gplayer.collections.List<String>(
        )
        
        for (trackId in this._tracksMapping)
        {
            if (!com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(trackId)))
            {
                continue
            }
            var track: com.omnifret.gplayer.model.Track = this._tracksById.get(trackId)!!
            this.score.addTrack(track)
            trackIndexToTrackId.push(trackId)
        }
        var keySignature: com.omnifret.gplayer.core.IArrayTuple<com.omnifret.gplayer.model.KeySignature, com.omnifret.gplayer.model.KeySignatureType>
        for (barIds in this._barsOfMasterBar)
        {
            var staffIndex: Double = 0.0
            var trackIndex: Double = 0.0
            keySignature = com.omnifret.gplayer.core.ArrayTuple<com.omnifret.gplayer.model.KeySignature, com.omnifret.gplayer.model.KeySignatureType>(com.omnifret.gplayer.model.KeySignature.C, com.omnifret.gplayer.model.KeySignatureType.Major)
            if (this._transposeKeySignaturePerTrack.has(trackIndexToTrackId[(0).toInt()]))
            {
                keySignature = com.omnifret.gplayer.core.ArrayTuple<com.omnifret.gplayer.model.KeySignature, com.omnifret.gplayer.model.KeySignatureType>(com.omnifret.gplayer.model.ModelUtils.transposeKey(keySignature.v0, this._transposeKeySignaturePerTrack.get(trackIndexToTrackId[(0).toInt()])!!), keySignature.v1)
            }
            if (true) {
                var barIndex: Double = 0.0
                
                while(barIndex < barIds.length && trackIndex < this.score.tracks.length){
                    var barId: String = barIds[(barIndex).toInt()]
                    if (barId != com.omnifret.gplayer.importer.GpifParser._invalidId)
                    {
                        var bar: com.omnifret.gplayer.model.Bar = this._barsById.get(barId)!!
                        var track: com.omnifret.gplayer.model.Track = this.score.tracks[(trackIndex).toInt()]
                        var staff: com.omnifret.gplayer.model.Staff = track.staves[(staffIndex).toInt()]
                        staff.addBar(bar)
                        var masterBarIndex: Double = staff.bars.length - (1.0).toDouble()
                        if (this._keySignatures.has(masterBarIndex))
                        {
                            keySignature = this._keySignatures.get(masterBarIndex)!!
                            if (this._transposeKeySignaturePerTrack.has(trackIndexToTrackId[(trackIndex).toInt()]))
                            {
                                keySignature = com.omnifret.gplayer.core.ArrayTuple<com.omnifret.gplayer.model.KeySignature, com.omnifret.gplayer.model.KeySignatureType>(com.omnifret.gplayer.model.ModelUtils.transposeKey(keySignature.v0, this._transposeKeySignaturePerTrack.get(trackIndexToTrackId[(trackIndex).toInt()])!!), keySignature.v1)
                            }
                        }
                        bar.keySignature = keySignature.v0
                        bar.keySignatureType = keySignature.v1
                        if (this._doubleBars.has(bar.masterBar))
                        {
                            bar.barLineRight = com.omnifret.gplayer.model.BarLineStyle.LightLight
                        }
                        if (this._voicesOfBar.has(barId))
                        {
                            for (voiceId in this._voicesOfBar.get(barId)!!)
                            {
                                if (voiceId != com.omnifret.gplayer.importer.GpifParser._invalidId)
                                {
                                    var voice: com.omnifret.gplayer.model.Voice = this._voiceById.get(voiceId)!!
                                    bar.addVoice(voice)
                                    if (this._beatsOfVoice.has(voiceId))
                                    {
                                        for (beatId in this._beatsOfVoice.get(voiceId)!!)
                                        {
                                            if (beatId != com.omnifret.gplayer.importer.GpifParser._invalidId)
                                            {
                                                var beat: com.omnifret.gplayer.model.Beat = com.omnifret.gplayer.generated.model.BeatCloner.clone(this._beatById.get(beatId)!!)
                                                voice.addBeat(beat)
                                                var rhythmId: String = this._rhythmOfBeat.get(beatId)!!
                                                var rhythm: com.omnifret.gplayer.importer.GpifRhythm = this._rhythmById.get(rhythmId)!!
                                                beat.duration = rhythm.value
                                                beat.dots = rhythm.dots
                                                beat.tupletNumerator = rhythm.tupletNumerator
                                                beat.tupletDenominator = rhythm.tupletDenominator
                                                if (this._notesOfBeat.has(beatId))
                                                {
                                                    for (noteId in this._notesOfBeat.get(beatId)!!)
                                                    {
                                                        if (noteId != com.omnifret.gplayer.importer.GpifParser._invalidId)
                                                        {
                                                            var note: com.omnifret.gplayer.model.Note = com.omnifret.gplayer.generated.model.NoteCloner.clone(this._noteById.get(noteId)!!)
                                                            if (staff.isPercussion)
                                                            {
                                                                note.fret = -1.0
                                                                note.string = -1.0
                                                            }
                                                            else 
                                                            {
                                                                note.percussionArticulation = -1.0
                                                            }
                                                            beat.addNote(note)
                                                            if (this._tappedNotes.has(noteId))
                                                            {
                                                                beat.tap = true
                                                            }
                                                        }
                                                    }
                                                }
                                            }
                                        }
                                    }
                                }
                                else 
                                {
                                    var voice: com.omnifret.gplayer.model.Voice = com.omnifret.gplayer.model.Voice()
                                    bar.addVoice(voice)
                                    var beat: com.omnifret.gplayer.model.Beat = com.omnifret.gplayer.model.Beat()
                                    beat.isEmpty = true
                                    beat.duration = com.omnifret.gplayer.model.Duration.Quarter
                                    voice.addBeat(beat)
                                }
                            }
                        }
                        if (staffIndex == track.staves.length - (1.0).toDouble())
                        {
                            trackIndex++
                            staffIndex = 0.0
                        }
                        else 
                        {
                            staffIndex++
                        }
                        keySignature = com.omnifret.gplayer.core.ArrayTuple<com.omnifret.gplayer.model.KeySignature, com.omnifret.gplayer.model.KeySignatureType>(com.omnifret.gplayer.model.KeySignature.C, com.omnifret.gplayer.model.KeySignatureType.Major)
                        if (trackIndex < trackIndexToTrackId.length && this._transposeKeySignaturePerTrack.has(trackIndexToTrackId[(trackIndex).toInt()]))
                        {
                            keySignature = com.omnifret.gplayer.core.ArrayTuple<com.omnifret.gplayer.model.KeySignature, com.omnifret.gplayer.model.KeySignatureType>(com.omnifret.gplayer.model.ModelUtils.transposeKey(keySignature.v0, this._transposeKeySignaturePerTrack.get(trackIndexToTrackId[(trackIndex).toInt()])!!), keySignature.v1)
                        }
                    }
                    else 
                    {
                        trackIndex++
                    }
                    barIndex++
                }
            }
        }
        for (trackId in this._tracksMapping)
        {
            if (!com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(trackId)))
            {
                continue
            }
            var track: com.omnifret.gplayer.model.Track = this._tracksById.get(trackId)!!
            var hasPercussion: Boolean = false
            for (staff in track.staves)
            {
                if (staff.isPercussion)
                {
                    hasPercussion = true
                    break
                }
            }
            if (!hasPercussion)
            {
                track.percussionArticulations = com.omnifret.gplayer.collections.List<com.omnifret.gplayer.model.InstrumentArticulation>(
                )
                
            }
            if (this._automationsPerTrackIdAndBarIndex.has(trackId))
            {
                var trackAutomations: com.omnifret.gplayer.collections.DoubleObjectMap<com.omnifret.gplayer.collections.List<com.omnifret.gplayer.model.Automation>> = this._automationsPerTrackIdAndBarIndex.get(trackId)!!
                for ((barNumber, automations) in trackAutomations)
                {
                    if (track.staves.length > 0 && barNumber < track.staves[(0).toInt()].bars.length)
                    {
                        var bar: com.omnifret.gplayer.model.Bar = track.staves[(0).toInt()].bars[(barNumber).toInt()]
                        if (bar.voices.length > 0 && bar.voices[(0).toInt()].beats.length > 0)
                        {
                            var beat: com.omnifret.gplayer.model.Beat = bar.voices[(0).toInt()].beats[(0).toInt()]
                            for (a in automations)
                            {
                                var skip: Boolean = a.type == com.omnifret.gplayer.model.AutomationType.Bank && a.value == 0.0 && bar.index == 0.0
                                if (!skip)
                                {
                                    beat.automations.push(a)
                                }
                            }
                        }
                    }
                }
            }
            if (this._sustainPedalsPerTrackIdAndBarIndex.has(trackId))
            {
                var sustainPedals: com.omnifret.gplayer.collections.DoubleObjectMap<com.omnifret.gplayer.collections.List<com.omnifret.gplayer.model.SustainPedalMarker>> = this._sustainPedalsPerTrackIdAndBarIndex.get(trackId)!!
                for ((barNumber, markers) in sustainPedals)
                {
                    if (track.staves.length > 0 && barNumber < track.staves[(0).toInt()].bars.length)
                    {
                        var bar: com.omnifret.gplayer.model.Bar = track.staves[(0).toInt()].bars[(barNumber).toInt()]
                        bar.sustainPedals = markers
                    }
                }
            }
        }
        for ((barNumber, automations) in this._masterTrackAutomations)
        {
            var masterBar: com.omnifret.gplayer.model.MasterBar = this.score.masterBars[(barNumber).toInt()]
            if (true) {
                var i: Double = 0.0
                var j: Double = automations.length
                
                while(i < j){
                    var automation: com.omnifret.gplayer.model.Automation = automations[(i).toInt()]
                    when (automation.type)
                    {
                        com.omnifret.gplayer.model.AutomationType.Tempo -> 
                        {
                            masterBar.tempoAutomations.push(automation)
                        }
                        com.omnifret.gplayer.model.AutomationType.SyncPoint -> 
                        {
                            automation.syncPointValue!!.millisecondOffset -= this._backingTrackPadding
